    solution_template: "#include <iostream>\n#include <vector>\nusing namespace std;\n\nstruct TreeNode {\n  int val;\n  TreeNode *left, *right;\n  TreeNode(int v) : val(v), left(nullptr), right(nullptr) {}\n};\n\nvoid findPaths(TreeNode* r, int t, vector<int>& path, vector<vector<int>>& res) {\n  if (!r) return;\n  path.push_back(r->val);\n  if (!r->left && !r->right && t == r->val) res.push_back(path);\n  findPaths(r->left, t - r->val, path, res);\n  findPaths(r->right, t - r->val, path, res);\n  path.pop_back();\n}\n\nint main() {\n  int n, t; cin >> n;\n  int vals[n];\n  for (int i = 0; i < n; i++) cin >> vals[i];\n  TreeNode* nodes[n];\n  for (int i = 0; i < n; i++) nodes[i] = new TreeNode(vals[i]);\n  for (int i = 0; i < n; i++) {\n    if (2*i+1 < n && vals[2*i+1] != -1) nodes[i]->left = nodes[2*i+1];\n    if (2*i+2 < n && vals[2*i+2] != -1) nodes[i]->right = nodes[2*i+2];\n  }\n  cin >> t;\n\n  // DFS + backtracking\n\n  return 0;\n}",
    approach: "Path Sum II uses DFS with backtracking: maintain a current path, push node, recurse, pop node. At leaf, if sum matches target, record the path.\n\nDiagram:\n       1\n      / \\\n     2   3\n    / \\ / \\\n   4  5 6  7\n\nTarget=8:\nPaths explored:\n  1->2->4 sum=7 !=8\n  1->2->5 sum=8 -> record [1,2,5]\n  1->3->6 sum=10 !=8\n  1->3->7 sum=11 !=8\n\nOutput: 1 2 5\n\nTime O(n^2), Space O(n).",
